import { useActions, useValues } from 'kea'

import { IconRefresh } from '@posthog/icons'
import { LemonButton, LemonInputSelect, LemonSelect } from '@posthog/lemon-ui'

import { DateFilter } from 'lib/components/DateFilter/DateFilter'
import { FilterBar } from 'lib/components/FilterBar'
import { dayjs } from 'lib/dayjs'
import { formatDateRange } from 'lib/utils'

import { EndpointsUsageBreakdown } from '~/queries/schema/schema-general'
import { IntervalType } from '~/types'
import { DateMappingOption } from '~/types'

import { endpointsUsageLogic } from './endpointsUsageLogic'

const endpointsUsageDateMapping: DateMappingOption[] = [
    {
        key: 'Last 24 hours',
        values: ['-24h'],
        getFormattedDate: (date: dayjs.Dayjs): string => formatDateRange(date.subtract(24, 'h'), date.endOf('d')),
        defaultInterval: 'hour',
    },
    {
        key: 'Last 48 hours',
        values: ['-48h'],
        getFormattedDate: (date: dayjs.Dayjs): string => formatDateRange(date.subtract(48, 'h'), date.endOf('d')),
        defaultInterval: 'hour',
    },
    {
        key: 'Last 7 days',
        values: ['-7d'],
        getFormattedDate: (date: dayjs.Dayjs): string => formatDateRange(date.subtract(7, 'd'), date.endOf('d')),
        defaultInterval: 'day',
    },
    {
        key: 'Last 14 days',
        values: ['-14d'],
        getFormattedDate: (date: dayjs.Dayjs): string => formatDateRange(date.subtract(14, 'd'), date.endOf('d')),
        defaultInterval: 'day',
    },
    {
        key: 'Last 30 days',
        values: ['-30d'],
        getFormattedDate: (date: dayjs.Dayjs): string => formatDateRange(date.subtract(30, 'd'), date.endOf('d')),
        defaultInterval: 'day',
    },
    {
        key: 'Last 90 days',
        values: ['-90d'],
        getFormattedDate: (date: dayjs.Dayjs): string => formatDateRange(date.subtract(90, 'd'), date.endOf('d')),
        defaultInterval: 'day',
    },
    {
        key: 'Year to date',
        values: ['yStart'],
        getFormattedDate: (date: dayjs.Dayjs): string => formatDateRange(date.startOf('y'), date.endOf('d')),
        defaultInterval: 'day',
    },
]

const EndpointNameFilter = ({ tabId }: { tabId: string }): JSX.Element => {
    const { endpointNames, endpointNamesLoading, endpointFilter } = useValues(endpointsUsageLogic({ tabId }))
    const { setEndpointFilter } = useActions(endpointsUsageLogic({ tabId }))

    const options = endpointNames.map((name: string) => ({
        key: name,
        label: name,
        value: name,
    }))

    return (
        <LemonInputSelect
            title="Endpoints"
            autoWidth={false}
            popoverClassName="max-h-60 max-w-s overflow-y-auto"
            className="max-h-30 max-w-s overflow-y-auto"
            value={endpointFilter.map((v) => v.toString())}
            loading={endpointNamesLoading}
            onChange={(newValues: string[]) => {
                const selectedEndpoints = endpointNames.filter((name: string) => newValues.includes(name))
                setEndpointFilter(selectedEndpoints)
            }}
            mode="multiple"
            options={options}
            data-attr="endpoint-names-filter"
            bulkActions="select-and-clear-all"
            displayMode="count"
            placeholder="All endpoints"
        />
    )
}

const MaterializationTypeFilter = ({ tabId }: { tabId: string }): JSX.Element => {
    const { materializationType } = useValues(endpointsUsageLogic({ tabId }))
    const { setMaterializationType } = useActions(endpointsUsageLogic({ tabId }))

    return (
        <LemonSelect
            value={materializationType}
            onChange={setMaterializationType}
            options={[
                { value: null, label: 'All execution types' },
                { value: 'materialized', label: 'Materialized executions' },
                { value: 'inline', label: 'Direct executions' },
            ]}
            data-attr="materialization-type-filter"
            size="small"
            dropdownPlacement="bottom-end"
        />
    )
}

const IntervalFilter = ({ tabId }: { tabId: string }): JSX.Element => {
    const { interval } = useValues(endpointsUsageLogic({ tabId }))
    const { setInterval } = useActions(endpointsUsageLogic({ tabId }))

    return (
        <LemonSelect
            value={interval}
            onChange={setInterval}
            options={[
                { value: 'hour' as IntervalType, label: 'Hourly' },
                { value: 'day' as IntervalType, label: 'Daily' },
                { value: 'week' as IntervalType, label: 'Weekly' },
                { value: 'month' as IntervalType, label: 'Monthly' },
            ]}
            data-attr="interval-filter"
            size="small"
            dropdownPlacement="bottom-end"
        />
    )
}

const BreakdownFilter = ({ tabId }: { tabId: string }): JSX.Element => {
    const { breakdownBy } = useValues(endpointsUsageLogic({ tabId }))
    const { setBreakdownBy } = useActions(endpointsUsageLogic({ tabId }))

    return (
        <LemonSelect
            value={breakdownBy}
            onChange={setBreakdownBy}
            options={[
                { value: null, label: 'No breakdown' },
                { value: EndpointsUsageBreakdown.Endpoint, label: 'By endpoint' },
                { value: EndpointsUsageBreakdown.MaterializationType, label: 'By execution type' },
                { value: EndpointsUsageBreakdown.ApiKey, label: 'By API key' },
                { value: EndpointsUsageBreakdown.Status, label: 'By status' },
            ]}
            data-attr="breakdown-filter"
            size="small"
            dropdownPlacement="bottom-end"
        />
    )
}

const RefreshButton = ({ tabId }: { tabId: string }): JSX.Element => {
    const { canRefresh } = useValues(endpointsUsageLogic({ tabId }))
    const { refresh } = useActions(endpointsUsageLogic({ tabId }))

    return (
        <LemonButton
            icon={<IconRefresh />}
            size="small"
            type="secondary"
            tooltip="Refresh usage data."
            disabledReason={
                !canRefresh
                    ? 'You can refresh once every 15 minutes. Note that it is not realtime, and may be delayed a few minutes.'
                    : undefined
            }
            onClick={refresh}
            aria-label="Refresh usage data"
        >
            Refresh
        </LemonButton>
    )
}

export const EndpointsUsageFilters = ({ tabId }: { tabId: string }): JSX.Element => {
    const { dateFilter } = useValues(endpointsUsageLogic({ tabId }))
    const { setDates } = useActions(endpointsUsageLogic({ tabId }))

    return (
        <FilterBar
            className="m-0 px-0 rounded-none"
            left={
                <>
                    <DateFilter
                        dateFrom={dateFilter.dateFrom}
                        dateTo={dateFilter.dateTo}
                        onChange={setDates}
                        forceGranularity="day"
                        dateOptions={endpointsUsageDateMapping}
                    />
                    <EndpointNameFilter tabId={tabId} />
                </>
            }
            right={
                <>
                    <RefreshButton tabId={tabId} />
                    <MaterializationTypeFilter tabId={tabId} />
                    <IntervalFilter tabId={tabId} />
                    <BreakdownFilter tabId={tabId} />
                </>
            }
        />
    )
}

import { actions, connect, kea, key, path, props, reducers, selectors } from 'kea'
import { router } from 'kea-router'

import { dayjs } from 'lib/dayjs'
import { tabAwareActionToUrl } from 'lib/logic/scenes/tabAwareActionToUrl'
import { tabAwareUrlToAction } from 'lib/logic/scenes/tabAwareUrlToAction'
import { dateStringToDayJs } from 'lib/utils'
import { urls } from 'scenes/urls'

import {
    EndpointsUsageBreakdown,
    EndpointsUsageOverviewQuery,
    EndpointsUsageTableQuery,
    EndpointsUsageTrendsQuery,
    NodeKind,
} from '~/queries/schema/schema-general'
import { EndpointType, IntervalType } from '~/types'

import { endpointsLogic } from './endpointsLogic'
import type { endpointsUsageLogicType } from './endpointsUsageLogicType'

export const INITIAL_DATE_FROM = '-7d'
export const INITIAL_DATE_TO = null as string | null
export const INITIAL_INTERVAL: IntervalType = 'day'

export interface EndpointsUsageLogicProps {
    tabId: string
}

export const endpointsUsageLogic = kea<endpointsUsageLogicType>([
    path(['products', 'endpoints', 'frontend', 'endpointsUsageLogic']),
    props({} as EndpointsUsageLogicProps),
    key((props) => props.tabId),
    connect(({ tabId }: EndpointsUsageLogicProps) => ({
        values: [endpointsLogic({ tabId }), ['allEndpoints', 'allEndpointsLoading']],
    })),

    actions({
        setDates: (dateFrom: string | null, dateTo: string | null) => ({ dateFrom, dateTo }),
        setEndpointFilter: (endpointFilter: string[]) => ({ endpointFilter }),
        setMaterializationType: (materializationType: 'materialized' | 'inline' | null) => ({ materializationType }),
        setInterval: (interval: IntervalType) => ({ interval }),
        setBreakdownBy: (breakdownBy: EndpointsUsageBreakdown | null) => ({ breakdownBy }),
        refresh: true,
    }),

    reducers({
        dateFilter: [
            {
                dateFrom: INITIAL_DATE_FROM,
                dateTo: INITIAL_DATE_TO,
            } as { dateFrom: string | null; dateTo: string | null },
            {
                setDates: (_, { dateFrom, dateTo }) => ({ dateFrom, dateTo }),
            },
        ],
        endpointFilter: [
            [] as string[],
            {
                setEndpointFilter: (_, { endpointFilter }) => endpointFilter,
            },
        ],
        materializationType: [
            null as 'materialized' | 'inline' | null,
            {
                setMaterializationType: (_, { materializationType }) => materializationType,
            },
        ],
        interval: [
            INITIAL_INTERVAL as IntervalType,
            {
                setInterval: (_, { interval }) => interval,
            },
        ],
        breakdownBy: [
            null as EndpointsUsageBreakdown | null,
            {
                setBreakdownBy: (_, { breakdownBy }) => breakdownBy,
            },
        ],
        lastRefreshedAt: [
            null as number | null,
            {
                refresh: () => Date.now(),
            },
        ],
        refreshKey: [
            0,
            {
                refresh: (state) => state + 1,
            },
        ],
    }),

    selectors({
        endpointNames: [
            (s) => [s.allEndpoints],
            (allEndpoints: EndpointType[]): string[] =>
                allEndpoints
                    .filter((e) => e.last_executed_at)
                    .map((e) => e.name)
                    .sort(),
        ],
        endpointNamesLoading: [(s) => [s.allEndpointsLoading], (loading: boolean): boolean => loading],
        canRefresh: [
            (s) => [s.lastRefreshedAt],
            (lastRefreshedAt: number | null): boolean => {
                if (lastRefreshedAt === null) {
                    return true
                }
                return Date.now() - lastRefreshedAt >= 15 * 60 * 1000
            },
        ],
        dateRange: [
            (s) => [s.dateFilter],
            (dateFilter): { date_from: string | null; date_to: string | null } => {
                const dateFromDayjs = dateStringToDayJs(dateFilter.dateFrom)
                const dateToDayjs = dateFilter.dateTo ? dateStringToDayJs(dateFilter.dateTo) : null

                return {
                    date_from: dateFromDayjs?.format('YYYY-MM-DD') ?? dayjs().subtract(7, 'day').format('YYYY-MM-DD'),
                    date_to: dateToDayjs?.format('YYYY-MM-DD') ?? null,
                }
            },
        ],

        overviewQuery: [
            (s) => [s.dateRange, s.endpointFilter, s.materializationType],
            (dateRange, endpointFilter, materializationType): EndpointsUsageOverviewQuery => ({
                kind: NodeKind.EndpointsUsageOverviewQuery,
                dateRange,
                endpointNames: endpointFilter.length > 0 ? endpointFilter : undefined,
                materializationType,
                compareFilter: { compare: true },
            }),
        ],

        requestsTrendsQuery: [
            (s) => [s.dateRange, s.endpointFilter, s.materializationType, s.interval, s.breakdownBy],
            (dateRange, endpointFilter, materializationType, interval, breakdownBy): EndpointsUsageTrendsQuery => ({
                kind: NodeKind.EndpointsUsageTrendsQuery,
                dateRange,
                endpointNames: endpointFilter.length > 0 ? endpointFilter : undefined,
                materializationType,
                metric: 'requests',
                interval,
                breakdownBy: breakdownBy ?? undefined,
            }),
        ],

        bytesReadTrendsQuery: [
            (s) => [s.dateRange, s.endpointFilter, s.materializationType, s.interval, s.breakdownBy],
            (dateRange, endpointFilter, materializationType, interval, breakdownBy): EndpointsUsageTrendsQuery => ({
                kind: NodeKind.EndpointsUsageTrendsQuery,
                dateRange,
                endpointNames: endpointFilter.length > 0 ? endpointFilter : undefined,
                materializationType,
                metric: 'bytes_read',
                interval,
                breakdownBy: breakdownBy ?? undefined,
            }),
        ],

        cpuSecondsTrendsQuery: [
            (s) => [s.dateRange, s.endpointFilter, s.materializationType, s.interval, s.breakdownBy],
            (dateRange, endpointFilter, materializationType, interval, breakdownBy): EndpointsUsageTrendsQuery => ({
                kind: NodeKind.EndpointsUsageTrendsQuery,
                dateRange,
                endpointNames: endpointFilter.length > 0 ? endpointFilter : undefined,
                materializationType,
                metric: 'cpu_seconds',
                interval,
                breakdownBy: breakdownBy ?? undefined,
            }),
        ],

        queryDurationTrendsQuery: [
            (s) => [s.dateRange, s.endpointFilter, s.materializationType, s.interval, s.breakdownBy],
            (dateRange, endpointFilter, materializationType, interval, breakdownBy): EndpointsUsageTrendsQuery => ({
                kind: NodeKind.EndpointsUsageTrendsQuery,
                dateRange,
                endpointNames: endpointFilter.length > 0 ? endpointFilter : undefined,
                materializationType,
                metric: 'query_duration',
                interval,
                breakdownBy: breakdownBy ?? undefined,
            }),
        ],

        errorRateTrendsQuery: [
            (s) => [s.dateRange, s.endpointFilter, s.materializationType, s.interval, s.breakdownBy],
            (dateRange, endpointFilter, materializationType, interval, breakdownBy): EndpointsUsageTrendsQuery => ({
                kind: NodeKind.EndpointsUsageTrendsQuery,
                dateRange,
                endpointNames: endpointFilter.length > 0 ? endpointFilter : undefined,
                materializationType,
                metric: 'error_rate',
                interval,
                breakdownBy: breakdownBy ?? undefined,
            }),
        ],

        endpointTableQuery: [
            (s) => [s.dateRange, s.endpointFilter, s.materializationType],
            (dateRange, endpointFilter, materializationType): EndpointsUsageTableQuery => ({
                kind: NodeKind.EndpointsUsageTableQuery,
                dateRange,
                endpointNames: endpointFilter.length > 0 ? endpointFilter : undefined,
                materializationType,
                breakdownBy: EndpointsUsageBreakdown.Endpoint,
                orderBy: ['requests', 'DESC'],
                limit: 100,
            }),
        ],
    }),

    tabAwareActionToUrl(({ values }) => {
        const actionToUrl = ({
            dateFilter = values.dateFilter,
            endpointFilter = values.endpointFilter,
            materializationType = values.materializationType,
            interval = values.interval,
            breakdownBy = values.breakdownBy,
        }): [string, Record<string, any> | undefined, string | undefined] | undefined => {
            const { dateFrom, dateTo } = dateFilter
            const searchParams = { ...router.values.searchParams }

            if (dateFrom !== INITIAL_DATE_FROM) {
                searchParams.dateFrom = dateFrom
            } else {
                delete searchParams.dateFrom
            }

            if (dateTo !== INITIAL_DATE_TO) {
                searchParams.dateTo = dateTo
            } else {
                delete searchParams.dateTo
            }

            if (endpointFilter.length > 0) {
                searchParams.endpointFilter = endpointFilter.join(',')
            } else {
                delete searchParams.endpointFilter
            }

            if (materializationType !== null) {
                searchParams.materializationType = materializationType
            } else {
                delete searchParams.materializationType
            }

            if (interval !== INITIAL_INTERVAL) {
                searchParams.interval = interval
            } else {
                delete searchParams.interval
            }

            if (breakdownBy !== null) {
                searchParams.breakdownBy = breakdownBy
            } else {
                delete searchParams.breakdownBy
            }

            return [router.values.location.pathname, searchParams, router.values.location.hash]
        }

        return {
            setDates: actionToUrl,
            setEndpointFilter: actionToUrl,
            setMaterializationType: actionToUrl,
            setInterval: actionToUrl,
            setBreakdownBy: actionToUrl,
        }
    }),

    tabAwareUrlToAction(({ actions }) => ({
        [urls.endpointsUsage()]: (_, searchParams) => {
            const { dateFrom, dateTo, endpointFilter, materializationType, interval, breakdownBy } = searchParams
            actions.setDates(dateFrom ?? INITIAL_DATE_FROM, dateTo ?? INITIAL_DATE_TO)
            actions.setEndpointFilter(endpointFilter ? endpointFilter.split(',') : [])
            actions.setMaterializationType(materializationType ?? null)
            actions.setInterval(interval ?? INITIAL_INTERVAL)
            actions.setBreakdownBy(breakdownBy ?? null)
        },
    })),
])

